<?php
function parseXmlConfig($xmlString) {
    // Load the XML string into a SimpleXML object
    $xml = simplexml_load_string($xmlString);

    if ($xml === false) {
        throw new Exception('Error parsing XML.');
    }

    $settings = [];

    // Iterate through each child element in the XML
    foreach ($xml->children() as $child) {
        $tagName = (string)$child->getName();
        $tagValue = (string)$child;

        if (!empty($tagValue)) {
            $settings[$tagName] = $tagValue;
        }
    }

    return $settings;
}

// Example usage:
$xmlString = '<config><setting1>value1</setting1><setting2>value2</setting2></config>';
try {
    $configSettings = parseXmlConfig($xmlString);
    print_r($configSettings);
